# vault/policies/genai-service-prod.hcl
# Policy for the production GenAI service pod.
# Identity: Kubernetes ServiceAccount via Vault Kubernetes auth.

# Allow: read the LLM API keys this service calls
path "secret/data/genai/prod/openai/api-key" {
  capabilities = ["read"]
}
path "secret/data/genai/prod/anthropic/api-key" {
  capabilities = ["read"]
}

# Allow: read its own database credentials (if not using dynamic secrets)
path "secret/data/genai/prod/db/genai-service" {
  capabilities = ["read"]
}

# Allow: list its own path so ESO can enumerate keys
path "secret/metadata/genai/prod/*" {
  capabilities = ["list"]
}

# DENY: keys belonging to other services
path "secret/data/genai/prod/billing-service/*" {
  capabilities = ["deny"]
}

# DENY: staging and eval paths (belt-and-suspenders vs wildcard grant)
path "secret/data/genai/staging/*" {
  capabilities = ["deny"]
}
path "secret/data/genai/eval/*" {
  capabilities = ["deny"]
}

# DENY: any rotation or admin paths
path "secret/data/genai/+/+/api-key" {
  capabilities = ["deny"]
}

# scripts/analyze_vault_audit.py
# Parse Vault audit JSONL logs and alert on anomalous LLM key reads.
# Feed this from your log aggregator (Datadog, Splunk, CloudWatch Logs).

import json, sys, datetime
from collections import defaultdict

SENSITIVE_PATHS = {
    "secret/data/genai/prod/openai/api-key",
    "secret/data/genai/prod/anthropic/api-key",
}
EXPECTED_READERS = {
    "jwt-repo:org/genai-service:ref:refs/heads/main",   # deploy job
    "k8s-genai-service-prod",                           # prod pod (via ESO)
}
BUSINESS_HOURS = range(6, 22)  # UTC 06:00–22:00

def analyze_log(log_lines: list[str]) -> list[dict]:
    alerts = []
    reads_per_identity: dict[str, int] = defaultdict(int)

    for line in log_lines:
        try:
            entry = json.loads(line)
        except json.JSONDecodeError:
            continue

        if entry.get("type") != "response":
            continue

        request_path = entry.get("request", {}).get("path", "")
        if request_path not in SENSITIVE_PATHS:
            continue

        identity = entry.get("auth", {}).get("display_name", "unknown")
        ts = entry.get("time", "")
        reads_per_identity[identity] += 1

        # Alert: unexpected identity reading prod LLM key
        if identity not in EXPECTED_READERS:
            alerts.append({
                "severity": "HIGH",
                "reason": f"Unexpected identity '{identity}' read {request_path}",
                "ts": ts,
            })

        # Alert: read outside business hours (possible automated abuse)
        try:
            hour = datetime.datetime.fromisoformat(ts.rstrip("Z")).hour
            if hour not in BUSINESS_HOURS and "k8s" not in identity:
                alerts.append({
                    "severity": "MEDIUM",
                    "reason": f"Off-hours read of {request_path} by '{identity}' at {ts}",
                    "ts": ts,
                })
        except ValueError:
            pass

    # Alert: burst reads (rotation bot or key scanning)
    for identity, count in reads_per_identity.items():
        if count > 20:
            alerts.append({
                "severity": "HIGH",
                "reason": f"Burst reads: '{identity}' read prod LLM keys {count} times",
            })

    return alerts

if __name__ == "__main__":
    lines = sys.stdin.readlines()
    alerts = analyze_log(lines)
    for alert in alerts:
        print(f"[{alert['severity']}] {alert['reason']}")
    if any(a["severity"] == "HIGH" for a in alerts):
        sys.exit(1)
